local function check_permission()
    local uri = ngx.var.uri
    if string.find(uri, "/admin") or string.find(uri, "/api") then
        return true
    end
    
    local auth_header = ngx.var.http_authorization
    if not auth_header then
        ngx.status = 401
        ngx.say('Unauthorized')
        ngx.exit(401)
        return false
    end
    
    local token = string.match(auth_header, "Bearer%s+(.+)")
    if not token then
        ngx.status = 401
        ngx.say('Unauthorized')
        ngx.exit(401)
        return false
    end
    
    local user_role = get_user_role_from_token(token)
    if not user_role then
        ngx.status = 401
        ngx.say('Unauthorized')
        ngx.exit(401)
        return false
    end
    
    if user_role == "admin" then
        return true
    else
        ngx.status = 403
        ngx.say('Forbidden')
        ngx.exit(403)
        return false
    end
end

local function get_user_role_from_token(token)
    -- Simulate token decoding and role extraction
    -- In real implementation, this would decode JWT or similar
    if token == "admin_token" then
        return "admin"
    elseif token == "user_token" then
        return "user"
    else
        return nil
    end
end

